class Circle(val radius: Double) {
    val diameter: Double
        get() = radius * 2
}
val c = Circle(5.0)
println(c.diameter)

class BankAccount(initialBalance: Double) {
    private var balance = initialBalance
    fun deposit(amount: Double) { balance += amount }
    fun getBalance() = balance
}
val acc = BankAccount(100.0)
acc.deposit(50.0)
println(acc.getBalance())

open class Animal(val name: String) {
    open fun sound() = "..."
}
class Dog(name: String) : Animal(name) {
    override fun sound() = "Woof"
}
println(Dog("Rex").sound())

class Lamp(var on: Boolean = false) {
    fun toggle() { on = !on }
}
val lamp1 = Lamp()
val lamp2 = Lamp()
lamp1.toggle()
println(lamp1.on)
println(lamp2.on)
